#!/usr/bin/env python3
import os
import sys
import subprocess
import shlex
import socket
import json
from pathlib import Path

# Configuration
ENABLE_NMAP = False      # Set True if you have nmap installed and consent to run it
ENABLE_LYNIS = False     # Set True if you have lynis installed and consent to run it
NETWORK_INTERFACES = ["0.0.0.0", "::"]  # Addresses indicating public listening if no firewall/NAT restricting

def run(cmd):
    try:
        out = subprocess.check_output(shlex.split(cmd), stderr=subprocess.STDOUT, timeout=60)
        return out.decode(errors="ignore")
    except Exception as e:
        return f"ERROR: {e}"

def get_os_info():
    info = {}
    if sys.platform.startswith("linux"):
        info["platform"] = "linux"
        os_release = {}
        try:
            with open("/etc/os-release","r") as f:
                for line in f:
                    if "=" in line:
                        k, v = line.strip().split("=", 1)
                        os_release[k] = v.strip('"')
        except Exception:
            pass
        info["os_release"] = os_release
        info["kernel"] = run("uname -a").strip()
        # Try package managers
        if Path("/usr/bin/dpkg-query").exists():
            info["pkg_mgr"] = "dpkg"
        elif Path("/usr/bin/rpm").exists():
            info["pkg_mgr"] = "rpm"
        else:
            info["pkg_mgr"] = "unknown"
    elif sys.platform == "darwin":
        info["platform"] = "macos"
        info["product"] = run("sw_vers").strip()
        info["kernel"] = run("uname -a").strip()
        info["pkg_mgr"] = "brew" if shutil.which("brew") else "unknown"
    elif os.name == "nt":
        info["platform"] = "windows"
        info["ver"] = run("cmd /c ver").strip()
        info["systeminfo"] = run("systeminfo").strip()
        info["pkg_mgr"] = "winget" if shutil.which("winget") else "unknown"
    else:
        info["platform"] = sys.platform
    return info

def list_installed_packages(info):
    pkgs = []
    if info.get("platform") == "linux":
        if info.get("pkg_mgr") == "dpkg":
            out = run("dpkg-query -W -f='${Package} ${Version}\n'")
            for line in out.splitlines():
                if not line or line.startswith("ERROR"):
                    continue
                parts = line.split()
                if len(parts) >= 2:
                    pkgs.append({"name": parts[0], "version": " ".join(parts[1:])})
        elif info.get("pkg_mgr") == "rpm":
            out = run("rpm -qa --qf '%{NAME} %{VERSION}-%{RELEASE}\n'")
            for line in out.splitlines():
                if not line or line.startswith("ERROR"):
                    continue
                parts = line.split()
                if len(parts) >= 2:
                    pkgs.append({"name": parts[0], "version": " ".join(parts[1:])})
    # Other platforms omitted for brevity
    return pkgs

def check_world_writable(paths):
    findings = []
    for p in paths:
        pth = Path(p)
        if not pth.exists():
            continue
        for root, dirs, files in os.walk(p, followlinks=False):
            for name in dirs + files:
                full = Path(root) / name
                try:
                    mode = full.stat().st_mode
                    if mode & 0o002:
                        findings.append(str(full))
                except Exception:
                    continue
    return findings

def check_ssh_permissions():
    findings = []
    home = Path.home()
    ssh_dir = home / ".ssh"
    if ssh_dir.exists():
        try:
            mode = ssh_dir.stat().st_mode
            if mode & 0o077:
                findings.append(f"{ssh_dir} has overly permissive mode")
        except Exception:
            pass
        for key in ssh_dir.glob("id_*"):
            if key.is_file() and not key.name.endswith(".pub"):
                try:
                    mode = key.stat().st_mode
                    if mode & 0o077:
                        findings.append(f"{key} should be 600 (found {oct(mode & 0o777)})")
                except Exception:
                    continue
        auth = ssh_dir / "authorized_keys"
        if auth.exists():
            try:
                mode = auth.stat().st_mode
                if mode & 0o077:
                    findings.append(f"{auth} too permissive (should be 600 or 640)")
            except Exception:
                pass
    return findings

def list_listening_sockets():
    findings = []
    cmd_candidates = [
        "ss -tulpen",  # modern linux
        "ss -tuln",
        "netstat -tulpen",
        "netstat -tuln",
        "lsof -i -P -n"
    ]
    out = None
    for c in cmd_candidates:
        r = run(c)
        if not r.startswith("ERROR") and r.strip():
            out = r
            break
    if not out:
        return {"raw": "", "public_listeners": [], "note": "No socket tool available"}
    public = []
    for line in out.splitlines():
        low = line.lower()
        if any(addr in low for addr in ["0.0.0.0:", "[::]:"]):
            public.append(line)
    return {"raw": out, "public_listeners": public}

def check_suid_sgid():
    findings = []
    # SUID/SGID binaries can be risky if vulnerable
    try:
        out = run("find / -xdev \\( -perm -4000 -o -perm -2000 \\) -type f 2>/dev/null")
        for line in out.splitlines():
            if line and not line.startswith("ERROR"):
                findings.append(line.strip())
    except Exception:
        pass
    return findings

def check_core_dumps():
    findings = []
    # Check if core dumps are limited
    out = run("bash -lc 'ulimit -c'")
    if out.strip() not in ["0", "0\n"]:
        findings.append(f"Core dumps enabled (ulimit -c = {out.strip()}). Consider disabling in production.")
    return findings

def optional_nmap_quick():
    # Non-intrusive quick scan of localhost top ports
    res = {"enabled": ENABLE_NMAP, "output": ""}
    if not ENABLE_NMAP:
        return res
    out = run("nmap -sT -T3 --top-ports 100 127.0.0.1")
    res["output"] = out
    return res

def optional_lynis_audit():
    res = {"enabled": ENABLE_LYNIS, "output": ""}
    if not ENABLE_LYNIS:
        return res
    out = run("lynis audit system --quick --no-colors")
    res["output"] = out
    return res

def summarize_outdated(pkgs, max_show=25):
    # Heuristic: flag very old versions for common packages (no CVE DB here)
    suspects = []
    keywords = {
        "openssl": "Consider updating OpenSSL",
        "bash": "Check for Shellshock-era patches",
        "sudo": "Ensure sudo patched for recent advisories",
        "linux-image": "Kernel updates may contain security fixes",
        "glibc": "Critical library; keep current",
        "apache2": "Web server; ensure current",
        "nginx": "Web server; ensure current",
        "php": "Ensure supported branch",
        "python3": "Keep current minor version for security fixes",
        "openssh": "Ensure server and client are current",
    }
    for p in pkgs:
        name = p["name"].lower()
        for k, note in keywords.items():
            if k in name:
                suspects.append({"package": p["name"], "version": p["version"], "note": note})
                break
        if len(suspects) >= max_show:
            break
    return suspects

def main():
    report = {}
    info = get_os_info()
    report["system_info"] = info

    pkgs = list_installed_packages(info)
    report["packages_checked_count"] = len(pkgs)
    report["potentially_sensitive_outdated"] = summarize_outdated(pkgs)

    ww_paths = ["/etc", "/usr/local/bin", "/usr/local/sbin", "/var/www", "/opt"]
    report["world_writable"] = check_world_writable(ww_paths)

    report["ssh_permissions"] = check_ssh_permissions()

    sockets = list_listening_sockets()
    report["listening_sockets"] = sockets

    report["suid_sgid_binaries"] = check_suid_sgid()

    report["core_dumps"] = check_core_dumps()

    report["nmap_quick"] = optional_nmap_quick()
    report["lynis_quick"] = optional_lynis_audit()

    # Simple guidance
    guidance = []
    if report["world_writable"]:
        guidance.append("Restrict world-writable files; review each listed path and adjust permissions/ownership.")
    if report["ssh_permissions"]:
        guidance.append("Harden SSH file permissions (chmod 700 ~/.ssh; chmod 600 private keys and authorized_keys).")
    if sockets.get("public_listeners"):
        guidance.append("Review services listening on public interfaces; restrict to localhost or firewall as appropriate.")
    if report["suid_sgid_binaries"]:
        guidance.append("Audit SUID/SGID binaries; remove SUID where not required.")
    if report["potentially_sensitive_outdated"]:
        guidance.append("Update the listed core packages; verify against your distribution’s security advisories.")
    report["guidance"] = guidance

    print(json.dumps(report, indent=2))

if __name__ == "__main__":
    main()
