script.js:
const items = [
  {
    title: "Starry Night (Public Domain)",
    creator: "Vincent van Gogh",
    license: "public-domain",
    thumb: "https://upload.wikimedia.org/wikipedia/commons/thumb/e/ea/The_Starry_Night.jpg/640px-The_Starry_Night.jpg",
  },
  {
    title: "CC0 Landscape",
    creator: "John Doe",
    license: "cc0",
    thumb: "https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1080&auto=format&fit=crop",
  },
  {
    title: "Open Track",
    creator: "Artist X",
    license: "cc-by",
    thumb: "https://upload.wikimedia.org/wikipedia/commons/thumb/3/3f/Placeholder_view_vector.svg/640px-Placeholder_view_vector.svg.png",
  },
  {
    title: "Open Photo",
    creator: "Jane Smith",
    license: "cc-by-sa",
    thumb: "https://images.unsplash.com/photo-1519681393784-d120267933ba?q=80&w=1080&auto=format&fit=crop",
  },
];

const grid = document.getElementById("grid");
const search = document.getElementById("search");
const licenseFilter = document.getElementById("licenseFilter");

function render(list) {
  grid.innerHTML = "";
  list.forEach(item => {
    const card = document.createElement("article");
    card.className = "card";
    const media = document.createElement("img");
    media.src = item.thumb;
    media.alt = item.title;
    const body = document.createElement("div");
    body.className = "body";
    const h4 = document.createElement("h4");
    h4.textContent = item.title;
    const p = document.createElement("p");
    p.textContent = item.creator;
    const badge = document.createElement("span");
    badge.className = "badge";
    badge.textContent = item.license.replace("-", " ").toUpperCase();
    body.appendChild(h4);
    body.appendChild(p);
    body.appendChild(badge);
    card.appendChild(media);
    card.appendChild(body);
    grid.appendChild(card);
  });
}

function applyFilters() {
  const q = search.value.trim().toLowerCase();
  const lic = licenseFilter.value;
  const filtered = items.filter(item => {
    const matchesQ = !q || item.title.toLowerCase().includes(q) || item.creator.toLowerCase().includes(q);
    const matchesLic = !lic || item.license === lic;
    return matchesQ && matchesLic;
  });
  render(filtered);
}

search.addEventListener("input", applyFilters);
licenseFilter.addEventListener("change", applyFilters);
render(items);

document.getElementById("year").textContent = new Date().getFullYear();

Notes for lawful use:
