Code:

<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Exam Prep Assistant</title>
  <style>
    body { font-family: Arial, sans-serif; margin: 0; background: #f7f8fa; color: #222; }
    header { background: #4c6ef5; color: #fff; padding: 24px; }
    header h1 { margin: 0; }
    main { max-width: 1000px; margin: 24px auto; padding: 0 16px; }
    .card { background: #fff; border-radius: 8px; box-shadow: 0 4px 16px rgba(0,0,0,0.08); padding: 16px; margin-bottom: 16px; }
    .row { display: flex; gap: 16px; flex-wrap: wrap; }
    .col { flex: 1 1 300px; }
    button { background: #4c6ef5; color: #fff; border: none; padding: 10px 14px; border-radius: 6px; cursor: pointer; }
    button.secondary { background: #e0e7ff; color: #223; }
    input, textarea, select { width: 100%; padding: 8px; border: 1px solid #ddd; border-radius: 6px; }
    .pill { display: inline-block; background: #eef2ff; color: #223; padding: 4px 8px; border-radius: 999px; margin-right: 6px; }
    .hidden { display: none; }
    .quiz { margin-top: 8px; }
    .question { margin-bottom: 12px; }
    .timer { font-weight: bold; }
    footer { text-align: center; padding: 24px; color: #666; }
  </style>
</head>
<body>
  <header>
    <h1>Exam Prep Assistant</h1>
    <p>Prepare smarter with structured guides, practice questions, and mock exams.</p>
  </header>

  <main>
    <div class="card">
      <h2>Upload Topics</h2>
      <p>Paste your syllabus or topics. We’ll build a study plan with key concepts, definitions, and checkpoints.</p>
      <textarea id="topicsInput" rows="6" placeholder="e.g., Limits and continuity, Derivatives, Integrals, Series..."></textarea>
      <div style="margin-top:8px;">
        <button id="generatePlanBtn">Generate Study Plan</button>
      </div>
      <div id="studyPlan" class="hidden" style="margin-top:12px;"></div>
    </div>

    <div class="row">
      <div class="card col">
        <h2>Practice</h2>
        <p>Answer practice questions with instant feedback.</p>
        <select id="topicSelect"></select>
        <div id="practiceArea" class="quiz"></div>
        <button id="addPracticeBtn" class="secondary">Add Example Question</button>
      </div>

      <div class="card col">
        <h2>Mock Exam</h2>
        <p>Take a timed mock exam to simulate real conditions.</p>
        <label>Duration (minutes)</label>
        <input id="examDuration" type="number" min="5" value="10"/>
        <button id="startExamBtn">Start Mock Exam</button>
        <div id="examArea" class="hidden">
          <p class="timer">Time left: <span id="timeLeft">10:00</span></p>
          <div id="examQuestions"></div>
          <button id="submitExamBtn">Submit Exam</button>
        </div>
      </div>
    </div>

    <div class="card">
      <h2>Progress Dashboard</h2>
      <p>Track your topics, practice accuracy, and recent activity.</p>
      <div id="dashboard">
        <div id="topicPills"></div>
        <p>Practice accuracy: <span id="accuracy">0%</span></p>
        <p>Mock exams taken: <span id="examsTaken">0</span></p>
      </div>
      <button id="resetDataBtn" class="secondary">Reset Data</button>
    </div>
  </main>

  <footer>
    <small>Use this tool to study and prepare ethically. Don’t engage in academic dishonesty.</small>
  </footer>

  <script>
    const store = {
      topics: [],
      questions: {},
      practiceStats: { correct: 0, total: 0 },
      examsTaken: 0
    };

    // Helpers
    function save() { localStorage.setItem('prepStore', JSON.stringify(store)); }
    function load() {
      const s = localStorage.getItem('prepStore');
      if (s) { const obj = JSON.parse(s);
        Object.assign(store, obj);
      }
      renderDashboard();
      renderTopicSelect();
    }
    function renderDashboard() {
      const pills = document.getElementById('topicPills');
      pills.innerHTML = '';
      store.topics.forEach(t => {
        const el = document.createElement('span');
        el.className = 'pill';
        el.textContent = t;
        pills.appendChild(el);
      });
      const acc = store.practiceStats.total ? Math.round(100 * store.practiceStats.correct / store.practiceStats.total) : 0;
      document.getElementById('accuracy').textContent = acc + '%';
      document.getElementById('examsTaken').textContent = store.examsTaken;
    }
    function renderTopicSelect() {
      const sel = document.getElementById('topicSelect');
      sel.innerHTML = '';
      store.topics.forEach(t => {
        const o = document.createElement('option');
        o.value = t; o.textContent = t;
        sel.appendChild(o);
      });
    }

    // Study plan generation (basic)
    document.getElementById('generatePlanBtn').addEventListener('click', () => {
      const raw = document.getElementById('topicsInput').value.trim();
      if (!raw) { alert('Please paste topics'); return; }
      const topics = raw.split(/[,;\n]+/).map(t => t.trim()).filter(Boolean);
      store.topics = [...new Set(topics)];
      save();
      renderTopicSelect();
      renderDashboard();

      const planEl = document.getElementById('studyPlan');
      planEl.classList.remove('hidden');
      planEl.innerHTML = '';
      store.topics.forEach(t => {
        const section = document.createElement('div');
        section.style.marginBottom = '8px';
        const title = document.createElement('strong');
        title.textContent = t;
        const list = document.createElement('ul');
        ['Key definitions', 'Core examples', 'Common pitfalls', 'Checkpoint quiz'].forEach(i => {
          const li = document.createElement('li');
          li.textContent = i;
          list.appendChild(li);
        });
        section.appendChild(title);
        section.appendChild(list);
        planEl.appendChild(section);

        // Seed minimal question bank
        if (!store.questions[t]) {
          store.questions[t] = [
            { q: `Define ${t}.`, a: `Answer will vary; include formal definition and typical use.` },
            { q: `Give an example problem using ${t}.`, a: `Work through a representative example step by step.` }
          ];
        }
      });
      save();
    });

    // Practice area
    const practiceArea = document.getElementById('practiceArea');
    function renderPractice(topic) {
      practiceArea.innerHTML = '';
      if (!topic || !store.questions[topic] || store.questions[topic].length === 0) {
        practiceArea.textContent = 'No questions for this topic yet.';
        return;
      }
      store.questions[topic].forEach((item, idx) => {
        const div = document.createElement('div');
        div.className = 'question';
        const q = document.createElement('div');
        q.textContent = item.q;
        const input = document.createElement('textarea');
        input.rows = 3;
        const btn = document.createElement('button');
        btn.textContent = 'Check';
        const feedback = document.createElement('div');
        btn.addEventListener('click', () => {
          // Simple correctness heuristic (placeholder): non-empty -> correct
          const correct = input.value.trim().length > 0;
          store.practiceStats.total += 1;
          if (correct) store.practiceStats.correct += 1;
          save();
          renderDashboard();
          feedback.textContent = correct ? 'Looks good. Compare with sample answer: ' + item.a : 'Try to add more detail or structure.';
        });
        div.appendChild(q);
        div.appendChild(input);
        div.appendChild(btn);
        div.appendChild(feedback);
        practiceArea.appendChild(div);
      });
    }
    document.getElementById('topicSelect').addEventListener('change', (e) => renderPractice(e.target.value));
    document.getElementById('addPracticeBtn').addEventListener('click', () => {
      const topic = document.getElementById('topicSelect').value;
      if (!topic) { alert('Select a topic'); return; }
      const q = prompt('Enter a practice question for ' + topic);
      const a = prompt('Enter a sample answer or rubric');
      if (q && a) {
        store.questions[topic].push({ q, a });
        save();
        renderPractice(topic);
      }
    });

    // Mock exam
    let examTimer = null, timeRemaining = 0;
    function formatTime(s) {
      const m = Math.floor(s/60);
      const sec = s % 60;
      return `${String(m).padStart(2,'0')}:${String(sec).padStart(2,'0')}`;
    }
    document.getElementById('startExamBtn').addEventListener('click', () => {
      const minutes = parseInt(document.getElementById('examDuration').value, 10);
      if (!minutes || minutes < 1) { alert('Enter a valid duration'); return; }
      const area = document.getElementById('examArea');
      area.classList.remove('hidden');
      const questionsEl = document.getElementById('examQuestions');
      questionsEl.innerHTML = '';

      const selectedTopics = store.topics.slice(0, Math.min(5, store.topics.length));
      const examQs = [];
      selectedTopics.forEach(t => {
        const bank = store.questions[t] || [];
        if (bank.length) {
