import re

def mask_email(text):
    # Mask local-part except first and last character, keep domain
    def repl(m):
        local, domain = m.group(1), m.group(2)
        if len(local) <= 2:
            masked_local = local[0] + "*" * (len(local) - 1)
        else:
            masked_local = local[0] + "*" * (len(local) - 2) + local[-1]
        return masked_local + "@" + domain
    email_pattern = re.compile(r'\b([A-Za-z0-9._%+-]+)@([A-Za-z0-9.-]+\.[A-Za-z]{2,})\b')
    return email_pattern.sub(repl, text)

def mask_phone(text):
    # Normalize and mask digits, reveal last 4
    def repl(m):
        digits = re.sub(r'\D', '', m.group(0))
        if len(digits) < 7:
            return "***"
        masked = "*" * (len(digits) - 4) + digits[-4:]
        return masked
    phone_pattern = re.compile(r'\b(?:\+?\d{1,3}[\s-]?)?(?:\(?\d{3}\)?[\s-]?\d{3}[\s-]?\d{4})\b')
    return phone_pattern.sub(repl, text)

def mask_credit_card(text):
    # Mask all but last 4 digits of 13-19 digit sequences
    def repl(m):
        digits = re.sub(r'\D', '', m.group(0))
        if 13 <= len(digits) <= 19:
            masked = "*" * (len(digits) - 4) + digits[-4:]
            return masked
        return "***"
    cc_pattern = re.compile(r'\b(?:\d[ -]?){13,19}\b')
    return cc_pattern.sub(repl, text)

def mask_ssn(text):
    # US SSN format: XXX-XX-XXXX or 9 digits
    def repl(m):
        digits = re.sub(r'\D', '', m.group(0))
        if len(digits) == 9:
            return "***-**-" + digits[-4:]
        return "***"
    ssn_pattern = re.compile(r'\b(?:\d{3}-\d{2}-\d{4}|\d{9})\b')
    return ssn_pattern.sub(repl, text)

def mask_names(text, sensitive_names=None):
    # Simple heuristic masking for a provided list of names
    if not sensitive_names:
        return text
    def mask_word(word):
        if len(word) <= 2:
            return word[0] + "*" * (len(word) - 1)
        return word[0] + "*" * (len(word) - 2) + word[-1]
    for name in sensitive_names:
        pattern = re.compile(r'\b' + re.escape(name) + r'\b', flags=re.IGNORECASE)
        text = pattern.sub(lambda m: mask_word(m.group(0)), text)
