def STeALS(data_records):
    """
    Mask sensitive information in a list of records (dicts).
    Fields masked: email, phone, ssn, credit_card, first_name, last_name.
    Returns a new list with masked values.
    """
    def mask_email(email):
        if not isinstance(email, str) or "@" not in email:
            return email
        local, domain = email.split("@", 1)
        if not local:
            return "*" * 3 + "@" + domain
        return local[0] + "*" * max(3, len(local) - 1) + "@" + domain

    def mask_phone(phone):
        s = "".join(ch for ch in str(phone) if ch.isdigit())
        if len(s) <= 4:
            masked = "*" * len(s)
        else:
            masked = "*" * (len(s) - 4) + s[-4:]
        # Reformat to standard mask
        return masked

    def mask_ssn(ssn):
        s = "".join(ch for ch in str(ssn) if ch.isdigit())
        if len(s) <= 4:
            return "*" * len(s)
        return "***-**-" + s[-4:]

    def mask_card(card):
        s = "".join(ch for ch in str(card) if ch.isdigit())
        if len(s) <= 4:
            return "*" * len(s)
        return "*" * (len(s) - 4) + s[-4:]

    def mask_name(name):
        if not isinstance(name, str) or len(name) == 0:
            return name
        return name[0] + "*" * (len(name) - 1)

    masked_records = []
    for rec in data_records:
        m = dict(rec)  # shallow copy
        if "email" in m:
            m["email"] = mask_email(m["email"])
        if "phone" in m:
            m["phone"] = mask_phone(m["phone"])
        if "ssn" in m:
            m["ssn"] = mask_ssn(m["ssn"])
        if "credit_card" in m:
            m["credit_card"] = mask_card(m["credit_card"])
        if "first_name" in m:
            m["first_name"] = mask_name(m["first_name"])
        if "last_name" in m:
            m["last_name"] = mask_name(m["last_name"])
        masked_records.append(m)
    return masked_records

# Example usage:
