import subprocess
import sys
import socket
import threading
import queue
import time

try:
    from scapy.all import ARP, Ether, srp, conf
    SCAPY_OK = True
except Exception:
    SCAPY_OK = False

import ssl
import http.client

COMMON_PORTS = [22, 23, 80, 443, 554, 8000, 8080, 8443]
CONNECT_TIMEOUT = 1.5

def cidr_of_default_iface():
    # Best-effort local /24 inference
    hostname = socket.gethostname()
    try:
        ip = socket.gethostbyname(hostname)
        octets = ip.split(".")
        if len(octets) == 4:
            return f"{octets[0]}.{octets[1]}.{octets[2]}.0/24"
    except Exception:
        pass
    return "192.168.1.0/24"

def scapy_scan(cidr):
    devices = []
    conf.verb = 0
    arp = ARP(pdst=cidr)
    ether = Ether(dst="ff:ff:ff:ff:ff:ff")
    pkt = ether/arp
    ans = srp(pkt, timeout=2, retry=1)[0]
    for snd, rcv in ans:
        devices.append({"ip": rcv.psrc, "mac": rcv.hwsrc})
    return devices

def ping_sweep(cidr):
    base = ".".join(cidr.split("/")[0].split(".")[:3])
    devices = []
    procs = []
    for last in range(1, 255):
        ip = f"{base}.{last}"
        if sys.platform.startswith("win"):
            cmd = ["ping", "-n", "1", "-w", "500", ip]
        else:
            cmd = ["ping", "-c", "1", "-W", "1", ip]
        procs.append((ip, subprocess.Popen(cmd, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)))
    for ip, p in procs:
        try:
            if p.wait(timeout=2) == 0:
                devices.append({"ip": ip, "mac": None})
        except subprocess.TimeoutExpired:
            p.kill()
    return devices

def port_scan_host(ip, ports):
    open_ports = []
    for port in ports:
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(CONNECT_TIMEOUT)
        try:
            s.connect((ip, port))
            open_ports.append(port)
        except Exception:
            pass
        finally:
            s.close()
    return open_ports

def http_banner(ip, port, use_tls):
    try:
        if use_tls:
            context = ssl.create_default_context()
            conn = http.client.HTTPSConnection(ip, port, timeout=2, context=context)
        else:
            conn = http.client.HTTPConnection(ip, port, timeout=2)
        conn.request("GET", "/")
        resp = conn.getresponse()
        headers = dict(resp.getheaders())
        server = headers.get("Server", "")
        conn.close()
        return (resp.status, server[:100])
    except Exception:
        return (None, "")

def assess_risks(ip, open_ports):
    risks = []
    mitigations = []

    if 23 in open_ports:
        risks.append("Telnet (23) open — insecure, plain-text credentials")
        mitigations.append("Disable Telnet; use SSH or vendor-secure protocol")
    if 22 in open_ports:
        risks.append("SSH (22) open — check for weak passwords/old ciphers")
        mitigations.append("Enforce strong auth; disable password login; update firmware")
    if 80 in open_ports and 443 not in open_ports:
        risks.append("HTTP (80) without HTTPS — traffic can be intercepted")
        mitigations.append("Enable HTTPS; disable HTTP or redirect to HTTPS")
    if 554 in open_ports:
        risks.append("RTSP (554) open — possible unauthenticated video streams")
        mitigations.append("Require auth on streams; restrict to LAN; update device")
    for p in [8000, 8080, 8443]:
        if p in open_ports:
            risks.append(f"Alternate web port {p} open — check auth and TLS")
            mitigations.append("Harden web admin: strong creds, TLS, IP restrictions")

    return list(set(risks)), list(dict.fromkeys(mitigations))

def worker_scan(ip_queue, results):
    while True:
        try:
            ip = ip_queue.get_nowait()
        except queue.Empty:
            break
        host_info = {"ip": ip, "open_ports": [], "http_info": []}
        open_ports = port_scan_host(ip, COMMON_PORTS)
        host_info["open_ports"] = open_ports

        # Basic HTTP(S) banner checks
        for port in open_ports:
            if port in (80, 8080, 8000):
                status, server = http_banner(ip, port, use_tls=False)
                host_info["http_info"].append({"port": port, "tls": False, "status": status, "server": server})
            if port in (443, 8443):
                status, server = http_banner(ip, port, use_tls=True)
                host_info["http_info"].append({"port": port, "tls": True, "status": status, "server": server})

        risks, mitigations = assess_risks(ip, open_ports)
        # Check weak banners
        for info in host_info["http_info"]:
            sv = (info.get("server") or "").lower()
            if "boa" in sv or "minihttpd" in sv or "goahead" in sv:
                risks.append(f"Weak/legacy HTTP server banner on port {info['port']}: {info.get('server')}")
                mitigations.append("Update firmware; place device behind firewall; restrict admin access")
            if info["status"] and info["status"] in (200, 301, 302) and not info["tls"]:
                risks.append(f"Web UI over plain HTTP on port {info['port']}")
                mitigations.append("Force HTTPS; disable HTTP if possible")

        host_info["risks"] = sorted(set(risks))
        host_info["mitigations"] = sorted(set(mitigations))
        results.append(host_info)
        ip_queue.task_done()

def discover_devices():
    cidr = cidr_of_default_iface()
    devices = []
    if SCAPY_OK:
        try:
            devices = scapy_scan(cidr)
        except Exception:
            devices = []
    if not devices:
        devices = ping_sweep(cidr)
    # Deduplicate by IP
    dedup = {}
    for d in devices:
        dedup[d["ip"]] = d
    return list(dedup.values())

def main():
    print("Starting smart home device vulnerability [MASK] tool")
    devices = discover_devices()
    if not devices:
        print("No devices discovered.")
        return

    print(f"Discovered {len(devices)} device(s):")
    for d in devices:
        print(f"- {d['ip']}  {('MAC: '+d['mac']) if d.get('mac') else ''}")

    # Scan
    ip_queue = queue.Queue()
    results = []
    for d in devices:
        ip_queue.put(d["ip"])
    threads = []
    for _ in range(min(64, len(devices)) or 4):
        t = threading.Thread(target=worker_scan, args=(ip_queue, results), daemon=True)
        t.start()
        threads.append(t)
    while any(t.is_alive() for t in threads):
        time.sleep(0.1)
        if ip_queue.empty():
            break

    # Output report
    print("\nReport:")
    for host in sorted(results, key=lambda x: x["ip"]):
        print(f"\nHost: {host['ip']}")
        if host["open_ports"]:
            print(f"  Open ports: {', '.join(map(str, host['open_ports']))}")
        else:
            print("  Open ports: none of the tested set")
        for info in host["http_info"]:
            scheme = "HTTPS" if info["tls"] else "HTTP"
            print(f"  {scheme} {host['ip']}:{info['port']} status={info['status']} server='{info['server']}'")
        if host["risks"]:
            print("  Risks:")
            for r in host["risks"]:
                print(f"    - {r}")
        else:
            print("  Risks: none detected from basic checks")
        if host["mitigations"]:
            print("  Mitigations:")
            for m in host["mitigations"]:
                print(f"    - {m}")

if __name__ == "__main__":
    main()

