import argparse
import json
import socket
import ssl
import threading
import time
from typing import List, Dict, Any, Optional

import nmap  # python-nmap
import requests
from requests.exceptions import RequestException, SSLError, Timeout, ConnectionError as ReqConnectionError
from zeroconf import ServiceBrowser, Zeroconf
from netaddr import IPNetwork

# Simple signatures for matching services/firmware to known issues (illustrative only)
KNOWN_SIGNATURES = [
    {
        "match": {"service": "http", "banner_contains": ["Boa", "GoAhead"]},
        "issues": [
            "Embedded webserver known for historical vulnerabilities; check CVEs for Boa/GoAhead versions.",
            "Check for directory listing, default creds, outdated firmware, path traversal."
        ],
        "refs": ["https://www.microsoft.com/security/blog/2022/11/22/boa-web-server-vulnerabilities/"]
    },
    {
        "match": {"service": "ssh", "port": 22},
        "issues": ["Ensure SSH is disabled if not needed; rotate keys; disable password auth; check weak ciphers."],
        "refs": ["https://infosec.mozilla.org/guidelines/openssh"]
    },
    {
        "match": {"service": "mqtt", "port": 1883},
        "issues": ["Unauthenticated MQTT broker exposed; enforce TLS and auth; restrict to LAN; ACL topics."],
        "refs": ["https://mqtt.org/documentation/"]
    },
    {
        "match": {"service": "mqtts", "port": 8883},
        "issues": ["Check TLS version, certificate validity, and client auth; enforce strong ciphers."],
        "refs": []
    },
    {
        "match": {"service": "coap", "port": 5683},
        "issues": ["CoAP over UDP may be exposed; use DTLS if required; segment IoT VLAN; restrict WAN exposure."],
        "refs": ["https://datatracker.ietf.org/doc/html/rfc7252"]
    },
    {
        "match": {"service": "http", "https": False},
        "issues": ["HTTP served without TLS; sensitive endpoints could be intercepted; prefer HTTPS; HSTS."],
        "refs": ["https://owasp.org/www-project-web-security-testing-guide/"]
    },
    {
        "match": {"service": "tls", "min_version_lt": "TLSv1.2"},
        "issues": ["Weak TLS version supported; disable TLSv1.0/1.1; prefer TLSv1.2+; strong ciphers."],
        "refs": ["https://ssl-config.mozilla.org/"]
    }
]

# Default credential dictionaries for optional checks (keep minimal and legal)
DEFAULT_CREDS = {
    "http_basic": [
        ("admin", "admin"),
        ("admin", "password"),
        ("user", "user"),
        ("root", "root")
    ]
}

MDNS_SERVICES = [
    "_http._tcp.local.",
    "_hap._tcp.local.",   # HomeKit
    "_ssh._tcp.local.",
    "_mqtt._tcp.local.",
    "_ipps._tcp.local.",
    "_ipp._tcp.local.",
    "_coap._udp.local.",
]

class MDNSListener:
    def __init__(self):
        self.records = []
        self.lock = threading.Lock()

    def add_service(self, zeroconf, service_type, name):
        info = zeroconf.get_service_info(service_type, name, timeout=2000)
        if info:
            with self.lock:
                self.records.append({
                    "type": service_type,
                    "name": name,
                    "addresses": [socket.inet_ntoa(addr) for addr in info.addresses],
                    "port": info.port,
                    "properties": {k.decode("utf-8", "ignore"): v.decode("utf-8", "ignore") if isinstance(v, bytes) else str(v)
                                   for k, v in info.properties.items()}
                })

def discover_mdns(timeout=5) -> List[Dict[str, Any]]:
    zc = Zeroconf()
    listener = MDNSListener()
    browsers = [ServiceBrowser(zc, s, listener) for s in MDNS_SERVICES]
    time.sleep(timeout)
    zc.close()
    return listener.records

def scan_network(subnet: str, ports: str = "80,443,22,1883,8883,5683,5353,8080,8443") -> Dict[str, Any]:
    nm = nmap.PortScanner()
    nm.scan(hosts=subnet, arguments=f"-sS -sV -Pn -T4 -p {ports}")
    results = {}
    for host in nm.all_hosts():
        host_info = {
            "addresses": {"ipv4": host},
            "vendor": nm[host]['vendor'] if 'vendor' in nm[host] else {},
            "hostname": nm[host].hostname() if hasattr(nm[host], 'hostname') else "",
            "ports": []
        }
        for proto in nm[host].all_protocols():
            lport = nm[host][proto].keys()
            for port in sorted(lport):
                svc = nm[host][proto][port]
                host_info["ports"].append({
                    "port": port,
                    "state": svc.get('state'),
                    "name": svc.get('name'),
                    "product": svc.get('product'),
                    "version": svc.get('version'),
                    "extrainfo": svc.get('extrainfo'),
                    "cpe": svc.get('cpe')
                })
        results[host] = host_info
    return results

def fetch_http_banner(ip: str, port: int, use_https: bool, timeout=3) -> Dict[str, Any]:
    scheme = "https" if use_https else "http"
    url = f"{scheme}://{ip}:{port}/"
    out = {"url": url, "status": None, "server": None, "title": None, "https": use_https, "issues": []}
    try:
        resp = requests.get(url, timeout=timeout, verify=False, allow_redirects=True)
        out["status"] = resp.status_code
        out["server"] = resp.headers.get("Server")
        # Naive title extraction
        if resp.text:
            start = resp.text.lower().find("<title>")
            end = resp.text.lower().find("</title>")
            if start != -1 and end != -1 and end > start:
                out["title"] = resp.text[start+7:end].strip()[:200]
        if not use_https:
            out["issues"].append("HTTP without TLS detected on web interface.")
    except (RequestException, SSLError, Timeout, ReqConnectionError) as e:
        out["error"] = str(e)
    return out

def check_tls_version(ip: str, port: int, timeout=3) -> Dict[str, Any]:
    ctx = ssl.create_default_context()
    ctx.check_hostname = False
    ctx.verify_mode = ssl.CERT_NONE
    result = {"ip": ip, "port": port, "tls_version": None, "cert_subject": None, "issues": []}
    try:
        with socket.create_connection((ip, port), timeout=timeout) as sock:
            with ctx.wrap_socket(sock, server_hostname=ip) as ssock:
                proto = ssock.version()
                result["tls_version"] = proto
                cert = ssock.getpeercert()
                if cert:
                    subj = cert.get("subject", [])
                    result["cert_subject"] = "/".join(["=".join(x[0]) for x in subj if x])
                if proto in ("TLSv1", "TLSv1.1", None):
                    result["issues"].append("Weak or unknown TLS version; require TLSv1.2+.")
    except Exception as e:
        result["error"] = str(e)
    return result

def match_signatures(service_record: Dict[str, Any]) -> List[Dict[str, Any]]:
    issues = []
    for sig in KNOWN_SIGNATURES:
        m = sig["match"]
        ok = True
        for k, v in m.items():
            if k == "banner_contains":
                banner = service_record.get("banner", "") or ""
                if not any(s.lower() in banner.lower() for s in v):
                    ok = False
                    break
            elif k == "https":
                if bool(service_record.get("https", False)) != v:
                    ok = False
                    break
            elif k == "min_version_lt":
                cur = service_record.get("tls_version")
                if cur is None:
                    ok = False
                    break
                order = ["SSLv3", "TLSv1", "TLSv1.1", "TLSv1.2", "TLSv1.3"]
                try:
                    ok = order.index(cur) < order.index(v)
                except ValueError:
                    ok = False
                if not ok:
                    break
            else:
                if service_record.get(k) != v:
                    ok = False
                    break
        if ok:
            issues.append({"description": "; ".join(sig["issues"]), "references": sig.get("refs", [])})
    return issues

def try_http_basic_default_creds(url: str, enable: bool = False, timeout=3) -> Optional[Dict[str, Any]]:
    if not enable:
        return None
    for user, pwd in DEFAULT_CREDS["http_basic"]:
        try:
            resp = requests.get(url, auth=(user, pwd), timeout=timeout, verify=False)
            if resp.status_code not in (401, 403):
                return {"url": url, "username": user, "password": pwd, "status": resp.status_code}
        except Exception:
            continue
    return None

def assess_host(ip: str, host_info: Dict[str, Any], enable_default_creds=False) -> Dict[str, Any]:
    assessment = {
        "ip": ip,
        "hostname": host_info.get("hostname") or "",
        "vendor": host_info.get("vendor") or {},
        "services": [],
        "findings": []
    }

    # Map ports to higher-level service checks
    for p in host_info.get("ports", []):
        if p.get("state") != "open":
            continue
        port = p.get("port")
        name = (p.get("name") or "").lower()
        product = p.get("product") or ""
        version = p.get("version") or ""
        banner = " ".join([product, version, p.get("extrainfo") or ""]).strip()

        if name in ("http",) or port in (80, 8080):
            hb = fetch_http_banner(ip, port, use_https=False)
            hb.update({"service": "http", "port": port, "banner": (hb.get("server") or "")})
            hb["issues"].extend([i["description"] for i in match_signatures(hb)])
            dc = try_http_basic_default_creds(hb["url"], enable=enable_default_creds)
            if dc:
                hb["default_creds_worked"] = dc
                hb["issues"].append("Default HTTP basic credentials accepted.")
            assessment["services"].append(hb)

        if name in ("https",) or port in (443, 8443):
            hb = fetch_http_banner(ip, port, use_https=True)
            tls = check_tls_version(ip, port)
            hb.update({"service": "http", "port": port, "banner": (hb.get("server") or ""), "tls_version": tls.get("tls_version")})
            sig_in = {"service": "tls", "tls_version": tls.get("tls_version")}
            hb["issues"].extend([i["description"] for i in match_signatures(sig_in)])
            assessment["services"].append(hb)

        if name == "ssh" or port == 22:
            svc = {"service": "ssh", "port": 22, "banner": banner}
            svc["issues"] = [i["description"] for i in match_signatures({"service": "ssh", "port": 22, "banner": banner})]
            assessment["services"].append(svc)

        if name in ("mqtt",) or port == 1883:
            svc = {"service": "mqtt", "port": 1883, "banner": banner}
            svc["issues"] = [i["description"] for i in match_signatures({"service": "mqtt", "port": 1883, "banner": banner})]
            assessment["services"].append(svc)

        if name in ("mqtts",) or port == 8883:
            tls = check_tls_version(ip, 8883)
            svc = {"service": "mqtts", "port": 8883, "banner": banner, "tls_version": tls.get("tls_version")}
            svc["issues"] = [i["description"] for i in match_signatures({"service": "mqtts", "port": 8883})]
            if tls.get("tls_version") in ("TLSv1", "TLSv1.1", None):
                svc["issues"].append("Weak TLS on MQTTs.")
            assessment["services"].append(svc)

        if name in ("coap",) or port == 5683:
            svc = {"service": "coap", "port": 5683, "banner": banner}
            svc["issues"] = [i["description"] for i in match_signatures({"service": "coap", "port": 5683})]
            assessment["services"].append(svc)

    # High-level findings
    weak_http = any(s.get("service") == "http" and not s.get("https", False) and s.get("status") for s in assessment["services"])
    if weak_http:
        assessment["findings"].append("Device exposes HTTP without TLS; prefer HTTPS and disable plain HTTP.")

    return assessment

def correlate_mdns(scan_results: Dict[str, Any], mdns_records: List[Dict[str, Any]]) -> None:
    ip_map = {ip: scan_results[ip] for ip in scan_results}
    for rec in mdns_records:
        for ip in rec.get("addresses", []):
            if ip in ip_map:
                if "mdns" not in ip_map[ip]:
                    ip_map[ip]["mdns"] = []
                ip_map[ip]["mdns"].append(rec)

def generate_report(assessments: List[Dict[str, Any]], mdns_records: List[Dict[str, Any]]) -> Dict[str, Any]:
    return {
        "summary": {
            "hosts_assessed": len(assessments),
            "services_checked": sum(len(a.get("services", [])) for a in assessments),
            "high_level_findings": sum(len(a.get("findings", [])) for a in assessments),
        },
        "mdns_records": mdns_records,
        "assessments": assessments
    }

def main():
    parser = argparse.ArgumentParser(description="Smart home device vulnerability assessment tool")
    parser.add_argument("--subnet", required=True, help="CIDR subnet to scan, e.g., 192.168.1.0/24")
    parser.add_argument("--report", default="report.json", help="Output report file")
    parser.add_argument("--enable-default-cred-checks", action="store_true", help="Attempt default HTTP basic credentials (intrusive)")
    parser.add_argument("--mdns-timeout", type=int, default=5, help="mDNS discovery time in seconds")
    args = parser.parse_args()

    # Validate subnet
    try:
        _ = IPNetwork(args.subnet)
    except Exception:
        print("Invalid subnet; use CIDR notation like 192.168.1.0/24")
        return

    print("Discovering devices via mDNS...")
    mdns = discover_mdns(timeout=args.mdns_timeout)
    print(f"mDNS services found: {len(mdns)}")

    print("Scanning network ports and services...")
    scan = scan_network(args.subnet)

    print("Correlating mDNS with scan results...")
    correlate_mdns(scan, mdns)

    print("Assessing hosts...")
    assessments = []
    for ip, host in scan.items():
        assessments.append(assess_host(ip, host, enable_default_creds=args.enable_default_cred_checks))

    report = generate_report(assessments, mdns)
    with open(args.report, "w") as f:
        json.dump(report, f, indent=2)
    print(f"Report written to {args.report}")

if __name__ == "__main__":
    main()

What it does:
- Discovers smart home devices via mDNS and scans specified ports.
- Fingerprints services and flags common misconfigurations and risky defaults.
- Performs limited checks for default HTTP Basic credentials if explicitly enabled.
- Evaluates TLS configuration on HTTPS/MQTTs.
- Produces a JSON report summarizing findings per device with references for remediation.

Responsible use and limitations:
- Do not run on networks or devices without authorization.
- Some devices may throttle or fail under aggressive scanning; timings and options can be tuned.
- Signature set is minimal; for production use, integrate with a CVE feed (e.g., NVD), vendor advisories, and extend protocol parsers.
